#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";
import {
  ensureDirectory,
  listJsonFiles,
  nowIso,
  parseArgs,
  readJson,
  writeJson,
} from "./lib.mjs";

function usage() {
  return [
    "Usage: node scripts/memory/migrate-memory.mjs [options]",
    "Options:",
    "  --legacy-root <path>       (default: memory/legacy)",
    "  --target-root <path>       (default: memory)",
    "  --dry-run",
  ].join("\n");
}

function loadLegacyPatterns(legacyRoot) {
  const patternsDir = path.join(legacyRoot, "patterns");
  const files = [];
  if (!fs.existsSync(patternsDir)) {
    return files;
  }

  for (const name of fs.readdirSync(patternsDir)) {
    const fullPath = path.join(patternsDir, name);
    if (!fs.statSync(fullPath).isFile() || !name.endsWith(".md")) {
      continue;
    }
    files.push(fullPath);
  }

  return files;
}

function loadLegacyEpisodes(legacyRoot) {
  const episodesDir = path.join(legacyRoot, "episodes");
  const files = [];
  if (!fs.existsSync(episodesDir)) {
    return files;
  }

  for (const name of fs.readdirSync(episodesDir)) {
    const fullPath = path.join(episodesDir, name);
    if (!fs.statSync(fullPath).isFile()) {
      continue;
    }
    files.push(fullPath);
  }

  return files;
}

function convertPattern(patternPath) {
  const content = fs.readFileSync(patternPath, "utf8");
  const base = path.basename(patternPath, ".md");
  return {
    id: `strategy-${base}`,
    memory_type: "summary_l2",
    level: 2,
    topics: [base.replace(/[_-]+/g, " ")],
    summary: content.split("\n").slice(0, 8).join(" "),
    rationale: "Migrated from legacy patterns",
    provenance: {
      actor: "migrate-memory",
      timestamp: nowIso(),
    },
    derives_from: [path.relative(process.cwd(), patternPath).replace(/\\/g, "/")],
    source_kind: "track_b",
  };
}

function convertEpisode(episodePath) {
  const content = fs.readFileSync(episodePath, "utf8");
  const base = path.basename(episodePath, path.extname(episodePath));
  return {
    id: `decision-${base}`,
    memory_type: "decision",
    level: 0,
    topics: ["legacy-episode"],
    summary: content.split("\n").slice(0, 10).join(" "),
    rationale: "Migrated from legacy episodes",
    provenance: {
      actor: "migrate-memory",
      timestamp: nowIso(),
    },
    derives_from: [path.relative(process.cwd(), episodePath).replace(/\\/g, "/")],
    source_kind: "track_c",
  };
}

function writeConverted(targetDir, item, dryRun) {
  const filePath = path.join(targetDir, `${item.id}.json`);
  if (!dryRun) {
    ensureDirectory(targetDir);
    writeJson(filePath, item);
  }
  return filePath;
}

try {
  const options = parseArgs(process.argv.slice(2));
  if (options.help) {
    process.stdout.write(`${usage()}\n`);
    process.exit(0);
  }

  const legacyPatterns = loadLegacyPatterns(options.legacyRoot);
  const legacyEpisodes = loadLegacyEpisodes(options.legacyRoot);

  const converted = {
    l2: [],
    l0: [],
    skipped: [],
  };

  for (const patternPath of legacyPatterns) {
    const item = convertPattern(patternPath);
    const target = writeConverted(path.join(options.targetRoot, "l2"), item, options.dryRun);
    converted.l2.push({ source: patternPath, target });
  }

  for (const episodePath of legacyEpisodes) {
    const item = convertEpisode(episodePath);
    const target = writeConverted(path.join(options.targetRoot, "l0"), item, options.dryRun);
    converted.l0.push({ source: episodePath, target });
  }

  const report = {
    status: "ok",
    dry_run: options.dryRun,
    converted_l2: converted.l2.length,
    converted_l0: converted.l0.length,
    skipped: converted.skipped.length,
  };

  process.stdout.write(`${JSON.stringify(report)}\n`);
} catch (error) {
  process.stderr.write(`${error.message}\n`);
  process.stderr.write(`${usage()}\n`);
  process.exit(1);
}

